CREATE OR REPLACE FUNCTION OFSERM.DERIVATIVE_EQUITY_UNDERLYING_DATA_POP(
    P_V_BATCH_ID         VARCHAR2,
    P_V_MIS_DATE         VARCHAR2,
    P_V_RUN_ID           VARCHAR2,
    P_V_PROCESS_ID       VARCHAR2,
    P_V_RUN_EXECUTION_ID VARCHAR2,
    P_N_RUN_SKEY         VARCHAR2,
    P_V_TASK_ID          VARCHAR2
) RETURN VARCHAR2 AUTHID CURRENT_USER AS

    ld_mis_date   DATE          := TO_DATE(P_V_MIS_DATE, 'YYYYMMDD');
    ln_mis_date   NUMBER        := TO_NUMBER(P_V_MIS_DATE);
    ln_run_skey   NUMBER(5)     := TO_NUMBER(SUBSTR(P_N_RUN_SKEY, 8, LENGTH(P_N_RUN_SKEY)));
    lv_run_id     VARCHAR2(64)  := SUBSTR(P_V_RUN_ID, 8, LENGTH(P_V_RUN_ID));

BEGIN

    insert /*+APPEND*/ into FSI_CAP_DERIVATIVES(N_COUNTRY_SKEY,N_MIS_DATE_SKEY,N_ACCT_SKEY,N_D_CUST_INDUSTRY_SKEY,F_REG_CAP_INVST_IND,N_INSTRUMENT_SKEY,F_CORE_INVESTMENT_COMPANY_IND,N_CUST_SKEY,N_COUNTERPARTY_TYPE_SKEY,N_PROD_SKEY,F_REGULATORY_PARTY_INDICATOR,N_CCF_PERCENT,N_EFF_MATURITY,N_GAAP_SKEY,N_ORIGINAL_MATURITY,N_PARENT_ACCT_SKEY,N_RESIDUAL_MATURITY,N_RUN_SKEY,N_SHAREHOLDING_PERCENT,V_APPROACH_TYPE,V_CCY_CODE,V_DATA_SOURCE,V_UNDERLYING_DATA_IDENTIFIER,N_ENTITY_SKEY,N_CAP_APPROACH_TYPE_SKEY,N_CAP_RECORD_TYPE_SKEY,V_RECORD_TYPE,N_BASEL_PARTY_GRADE_SKEY,N_STD_COUNTERPARTY_TYPE_SKEY,N_REG_CAP_INDUSTRY_SKEY,N_REG_INDUSTRY_SKEY,N_BASEL_PROD_TYPE_SKEY,N_PD_PERCENT)SELECT  /*+PARALLEL (4)*/ to_char(DIM_COUNTRY.N_COUNTRY_SKEY),to_char(DIM_DATES.N_DATE_SKEY),to_char(DIM_EXPOSURE.N_ACCT_SKEY),to_char(DIM_INDUSTRY.N_D_CUST_INDUSTRY_SKEY),DIM_INSTRUMENT_CONTRACT.F_REG_CAP_INVST_IND,to_char(DIM_INSTRUMENT_CONTRACT.N_INSTRUMENT_SKEY),DIM_PARTY.F_CORE_INVESTMENT_COMPANY_IND,to_char(DIM_PARTY.N_PARTY_SKEY),to_char(DIM_PARTY_TYPE.N_PARTY_TYPE_SKEY),to_char(DIM_PRODUCT.N_PROD_SKEY),DIM_ORG_STRUCTURE_REG.F_REGULATORY_ENTITY_IND,1,CASE WHEN FSI_UNDERLYING_MODELING_INFO.N_EFF_MATURITY IS NULL THEN DAYS_BETWEEN(to_date('20260331','YYYYMMDD'),DIM_UNDERLYING.d_underlying_maturity_date,COALESCE (DIM_UNDERLYING.V_DAY_COUNT_IND_PAY, DIM_UNDERLYING.V_DAY_COUNT_IND_RCV)) ELSE FSI_UNDERLYING_MODELING_INFO.N_EFF_MATURITY END,FCT_ENTITY_INFO_CUST.N_GAAP_SKEY,DAYS_BETWEEN(DIM_INSTRUMENT_CONTRACT.D_MATURITY_DATE,DIM_INSTRUMENT_CONTRACT.D_ISSUE_DATE,DIM_INSTRUMENT_CONTRACT.V_DAY_COUNTER),DIM_PARENT_EXPOSURE.N_ACCT_SKEY,DAYS_BETWEEN(to_date('20260331','YYYYMMDD'),DIM_UNDERLYING.d_underlying_maturity_date,COALESCE (DIM_UNDERLYING.V_DAY_COUNT_IND_PAY, DIM_UNDERLYING.V_DAY_COUNT_IND_RCV)),'870',CASE WHEN DIM_BASEL_CAP_CONSL_APPR.V_BASEL_CAP_CONSL_APPR_CODE = 'PRCS' THEN FCT_ENTITY_INFO.N_SHAREHOLDING_PERCENT ELSE 1 END,FSI_BASEL_EXEC_APPR_DETAILS.V_APPROACH_TYPE_CODE,COALESCE (DIM_UNDERLYING.V_RCV_CCY,DIM_UNDERLYING.V_PAY_CCY),'STG_UNDERLYING_DTL','CIU',to_char(FCT_ENTITY_INFO.N_ENTITY_SKEY),to_char(FSI_CAP_APPROACH_TYPE_MASTER.N_CAP_APPROACH_TYPE_SKEY),to_char(FSI_CAP_RECORD_TYPE_MASTER.N_CAP_RECORD_TYPE_SKEY),FSI_CAP_RECORD_TYPE_MASTER.V_RECORD_TYPE,to_char(FSI_PARTY_GRADE_RECLASS.N_BASEL_GRADE_SKEY),to_char(FSI_PARTY_TYPE_CLASSIFICATION.N_STANDARD_PARTY_TYPE_SKEY),to_char(FSI_REG_CAP_INDUSTRY_RECLASS.N_REG_CAP_INDUSTRY_SKEY),to_char(FSI_REG_INDUSTRY_RECLASS.N_REG_INDUSTRY_SKEY),to_char(FSI_REG_PROD_TYPE_RECLASS.N_BASEL_PROD_TYPE_SKEY),to_char(FSI_UNDERLYING_MODELING_INFO.N_PD_PERCENT) FROM STG_UNDERLYING_DTL INNER JOIN DIM_DATES ON DIM_DATES.D_CALENDAR_DATE = to_date('20260331','YYYYMMDD')   AND STG_UNDERLYING_DTL.FIC_MIS_DATE = to_date('20260331','YYYYMMDD') INNER JOIN DIM_RUN ON DIM_RUN.N_RUN_SKEY = '870' LEFT OUTER JOIN DIM_UNDERLYING ON STG_UNDERLYING_DTL.V_INSTRUMENT_CODE = DIM_UNDERLYING.V_UNDERLYING_CODE   AND to_date('20260331','YYYYMMDD') BETWEEN DIM_UNDERLYING.D_RECORD_START_DATE AND DIM_UNDERLYING.D_RECORD_END_DATE JOIN DIM_EXPOSURE ON DIM_UNDERLYING.V_UNDERLYING_CODE = DIM_EXPOSURE.V_EXPOSURE_ID AND to_date('20260331','YYYYMMDD') BETWEEN DIM_EXPOSURE.D_RECORD_START_DATE AND DIM_EXPOSURE.D_RECORD_END_DATE LEFT OUTER JOIN DIM_ISSUE ON DIM_UNDERLYING.V_ISSUER_CODE = DIM_ISSUE.V_ISSUE_CODE AND to_date('20260331','YYYYMMDD') BETWEEN DIM_ISSUE.D_RECORD_START_DATE AND DIM_ISSUE.D_RECORD_END_DATE LEFT OUTER JOIN DIM_PRODUCT ON DIM_UNDERLYING.V_PROD_CODE = DIM_PRODUCT.V_PROD_CODE AND to_date('20260331','YYYYMMDD') BETWEEN DIM_PRODUCT.D_RECORD_START_DATE AND DIM_PRODUCT.D_RECORD_END_DATE LEFT OUTER JOIN DIM_EXPOSURE DIM_PARENT_EXPOSURE ON STG_UNDERLYING_DTL.V_CONTRACT_INSTRUMENT_CODE = DIM_PARENT_EXPOSURE.V_EXPOSURE_ID AND to_date('20260331','YYYYMMDD') BETWEEN DIM_PARENT_EXPOSURE.D_RECORD_START_DATE AND DIM_PARENT_EXPOSURE.D_RECORD_END_DATE LEFT OUTER JOIN DIM_PARTY ON COALESCE(DIM_UNDERLYING.V_ISSUER_CODE, 'MSG') = DIM_PARTY.V_PARTY_ID AND to_date('20260331','YYYYMMDD') BETWEEN DIM_PARTY.D_RECORD_START_DATE AND DIM_PARTY.D_RECORD_END_DATE INNER JOIN DIM_PARTY_TYPE ON COALESCE(DIM_PARTY.V_PARTY_TYPE, 'MSG') = DIM_PARTY_TYPE.V_PARTY_TYPE_CODE AND to_date('20260331','YYYYMMDD') BETWEEN DIM_PARTY_TYPE.D_RECORD_START_DATE AND DIM_PARTY_TYPE.D_RECORD_END_DATE LEFT OUTER JOIN DIM_COUNTRY ON COALESCE(DIM_EXPOSURE.V_COUNTRY_CODE, 'MSG') = DIM_COUNTRY.V_COUNTRY_ID AND to_date('20260331','YYYYMMDD') BETWEEN DIM_COUNTRY.D_RECORD_START_DATE AND DIM_COUNTRY.D_RECORD_END_DATE INNER JOIN FCT_ENTITY_INFO ON DIM_UNDERLYING.V_LV_CODE = FCT_ENTITY_INFO.V_ENTITY_CODE AND FCT_ENTITY_INFO.N_RUN_SKEY = '870' INNER JOIN DIM_BASEL_CAP_CONSL_APPR ON DIM_BASEL_CAP_CONSL_APPR.N_BASEL_CAP_CONSL_APPR_SKEY = FCT_ENTITY_INFO.N_BASEL_CAP_CONSL_APPR_SKEY AND DIM_BASEL_CAP_CONSL_APPR.V_BASEL_CAP_CONSL_APPR_CODE IN ( 'FLCS' ,'PRCS' ,'FAGR' ,'PRAGR' ) LEFT OUTER JOIN DIM_GEOGRAPHY ON COALESCE(DIM_PARTY.V_BRANCH_CODE, 'MSG') = DIM_GEOGRAPHY.V_ACCT_BRANCH_CODE AND to_date('20260331','YYYYMMDD') BETWEEN DIM_GEOGRAPHY.D_RECORD_START_DATE AND DIM_GEOGRAPHY.D_RECORD_END_DATE LEFT OUTER JOIN DIM_INDUSTRY ON DIM_INDUSTRY.V_D_CUST_INDUSTRY = COALESCE(DIM_PARTY.V_INDUSTRY_CODE, 'MSG') AND to_date('20260331','YYYYMMDD') BETWEEN DIM_INDUSTRY.D_RECORD_START_DATE AND DIM_INDUSTRY.D_RECORD_END_DATE LEFT OUTER JOIN RUN_EXE_PARAMETERS RUN_EXE_PARAMETERS_RCY ON RUN_EXE_PARAMETERS_RCY.N_RUN_SKEY = '870' AND RUN_EXE_PARAMETERS_RCY.V_PARAM_ID = 'RCY' LEFT OUTER JOIN SEC_POOL_MASTER ON STG_UNDERLYING_DTL.V_CONTRACT_INSTRUMENT_CODE = SEC_POOL_MASTER.V_SEC_POOL_ID AND to_date('20260331','YYYYMMDD') BETWEEN SEC_POOL_MASTER.D_RECORD_START_DATE AND SEC_POOL_MASTER.D_RECORD_END_DATE LEFT OUTER JOIN DIM_LOCATION ON DIM_LOCATION.V_LOCATION_CODE = DIM_PARTY.V_LOCATION_CODE AND to_date('20260331','YYYYMMDD') BETWEEN DIM_LOCATION.D_RECORD_START_DATE AND DIM_LOCATION.D_RECORD_END_DATE LEFT OUTER JOIN FSI_REG_PROD_TYPE_RECLASS ON FSI_REG_PROD_TYPE_RECLASS.N_MIS_DATE_SKEY = DIM_DATES.N_DATE_SKEY AND FSI_REG_PROD_TYPE_RECLASS.N_RUN_SKEY = '870' AND FSI_REG_PROD_TYPE_RECLASS.N_PROD_SKEY = DIM_PRODUCT.N_PROD_SKEY LEFT OUTER JOIN DIM_BASEL_PRODUCT_TYPE ON DIM_BASEL_PRODUCT_TYPE.N_BASEL_PROD_TYPE_SKEY = FSI_REG_PROD_TYPE_RECLASS.N_BASEL_PROD_TYPE_SKEY LEFT OUTER JOIN FSI_PARTY_TYPE_CLASSIFICATION ON FSI_PARTY_TYPE_CLASSIFICATION.N_MIS_DATE_SKEY = DIM_DATES.N_DATE_SKEY AND FSI_PARTY_TYPE_CLASSIFICATION.N_RUN_SKEY = '870' AND FSI_PARTY_TYPE_CLASSIFICATION.N_PARTY_TYPE_SKEY = DIM_PARTY_TYPE.N_PARTY_TYPE_SKEY LEFT OUTER JOIN DIM_INSTRUMENT_CONTRACT ON DIM_INSTRUMENT_CONTRACT.V_INSTRUMENT_CODE = STG_UNDERLYING_DTL.V_INSTRUMENT_CODE   AND to_date('20260331','YYYYMMDD') BETWEEN DIM_INSTRUMENT_CONTRACT.D_RECORD_START_DATE AND DIM_INSTRUMENT_CONTRACT.D_RECORD_END_DATE LEFT OUTER JOIN FSI_UNDERLYING_MODELING_INFO ON DIM_UNDERLYING.V_UNDERLYING_CODE = FSI_UNDERLYING_MODELING_INFO.V_UNDERLYING_CODE   AND to_date('20260331','YYYYMMDD') BETWEEN FSI_UNDERLYING_MODELING_INFO.D_RECORD_START_DATE AND FSI_UNDERLYING_MODELING_INFO.D_RECORD_END_DATE LEFT OUTER JOIN DIM_ORG_STRUCTURE DIM_ORG_STRUCTURE_REG ON DIM_ORG_STRUCTURE_REG.V_ENTITY_CODE = DIM_UNDERLYING.V_LV_CODE AND to_date('20260331','YYYYMMDD') BETWEEN DIM_ORG_STRUCTURE_REG.D_RECORD_START_DATE AND DIM_ORG_STRUCTURE_REG.D_RECORD_END_DATE LEFT OUTER JOIN DIM_LOB ON DIM_UNDERLYING.V_LOB_CODE = DIM_LOB.V_LOB_CODE   AND to_date('20260331','YYYYMMDD') BETWEEN DIM_LOB.D_RECORD_START_DATE AND DIM_LOB.D_RECORD_END_DATE LEFT OUTER JOIN FSI_CAP_RUN_EXE_PARAMETERS ON DIM_RUN.N_RUN_SKEY = FSI_CAP_RUN_EXE_PARAMETERS.N_RUN_SKEY AND DIM_DATES.n_date_skey = FSI_CAP_RUN_EXE_PARAMETERS.N_MIS_DATE_SKEY LEFT OUTER JOIN FSI_BASEL_EXEC_APPR_DETAILS ON FSI_BASEL_EXEC_APPR_DETAILS.N_MIS_DATE_SKEY = DIM_DATES.n_date_skey AND FSI_BASEL_EXEC_APPR_DETAILS.N_RUN_SKEY = '870' AND FSI_BASEL_EXEC_APPR_DETAILS.V_RISK_SUB_TYPE = 'NONSEC' LEFT OUTER JOIN RUN_PARAMETERS ON RUN_PARAMETERS.N_MIS_DATE_SKEY = DIM_DATES.n_date_skey AND RUN_PARAMETERS.N_RUN_SKEY = '870' AND FSI_BASEL_EXEC_APPR_DETAILS.N_RUN_PARAMETER_SKEY = RUN_PARAMETERS.N_RUN_PARAMETER_SKEY LEFT OUTER JOIN FSI_CAP_APPROACH_TYPE_MASTER ON FSI_CAP_APPROACH_TYPE_MASTER.V_APPROACH_TYPE = FSI_BASEL_EXEC_APPR_DETAILS.V_APPROACH_TYPE_CODE LEFT OUTER JOIN FSI_CAP_RECORD_TYPE_MASTER ON FSI_CAP_RECORD_TYPE_MASTER.V_RECORD_TYPE = 'DRV_NON_SEC_ULY' LEFT OUTER JOIN FSI_PARTY_GRADE_RECLASS ON FSI_PARTY_GRADE_RECLASS.N_PARTY_SKEY = DIM_PARTY.N_PARTY_SKEY AND FSI_PARTY_GRADE_RECLASS.N_RUN_SKEY = '870' AND FSI_PARTY_GRADE_RECLASS.N_MIS_DATE_SKEY = DIM_DATES.N_DATE_SKEY AND FSI_PARTY_GRADE_RECLASS.N_STANDARD_PARTY_TYPE_SKEY = FSI_PARTY_TYPE_CLASSIFICATION.N_STANDARD_PARTY_TYPE_SKEY LEFT OUTER JOIN FSI_REG_INDUSTRY_RECLASS ON FSI_REG_INDUSTRY_RECLASS.N_D_CUST_INDUSTRY_SKEY = DIM_INDUSTRY.N_D_CUST_INDUSTRY_SKEY AND FSI_REG_INDUSTRY_RECLASS.N_MIS_DATE_SKEY = DIM_DATES.N_DATE_SKEY AND FSI_REG_INDUSTRY_RECLASS.N_RUN_SKEY = '870' LEFT OUTER JOIN FCT_ENTITY_INFO FCT_ENTITY_INFO_CUST ON FCT_ENTITY_INFO_CUST.N_RUN_SKEY = '870' AND FCT_ENTITY_INFO_CUST.F_CAP_CONSL_PARENT_ENTITY_IND = 'Y' LEFT JOIN FSI_REG_CAP_INDUSTRY_RECLASS ON FSI_REG_CAP_INDUSTRY_RECLASS.N_D_CUST_INDUSTRY_SKEY = DIM_INDUSTRY.N_D_CUST_INDUSTRY_SKEY AND FSI_REG_CAP_INDUSTRY_RECLASS.N_RUN_SKEY = '870' WHERE 1=1 AND DIM_BASEL_PRODUCT_TYPE.V_BASEL_PROD_TYPE_CODE IN ( 'EQ' ,'EQC' ,'UCT' ,'BOLI' ) AND EXISTS ( SELECT 1 FROM FSI_CAP_ACCOUNT_LOAD_RUN_MAP WHERE FSI_CAP_ACCOUNT_LOAD_RUN_MAP.V_ACCOUNT_NUMBER = DIM_PARENT_EXPOSURE.V_EXPOSURE_ID AND FSI_CAP_ACCOUNT_LOAD_RUN_MAP.FIC_MIS_DATE = DIM_DATES.D_CALENDAR_DATE AND FSI_CAP_ACCOUNT_LOAD_RUN_MAP.N_RUN_SKEY = '870' ) AND DAYS_BETWEEN(to_date('20260331','YYYYMMDD'),DIM_UNDERLYING.d_underlying_maturity_date,COALESCE (DIM_UNDERLYING.V_DAY_COUNT_IND_PAY, DIM_UNDERLYING.V_DAY_COUNT_IND_RCV))>0 LOG ERRORS INTO FSI_CAP_DERIVATIVES$ ('1776768372730_7805204_20260331_1_Job_1583417047950') REJECT LIMIT 0;

    COMMIT;
    RETURN 'OK';

EXCEPTION
    WHEN OTHERS THEN
        ROLLBACK;
        RETURN 'FAIL: ' || SQLERRM;
END;
